/**
 * Tokenize an emoji string into single-glyph codepoint keys, e.g.:
 *   "🍅🍞" → ["1f345", "1f35e"]
 *   "🇧🇬" → ["1f1e7-1f1ec"]
 *   "🌶️" → ["1f336"]   (FE0F variation selector stripped)
 */
export function tokenizeEmoji(s: string): string[] {
  const out: string[] = [];
  const chars = [...s];
  let i = 0;
  while (i < chars.length) {
    const cp = chars[i].codePointAt(0)!;
    if (cp === 0xfe0f) { i++; continue; }
    if (cp >= 0x1f1e6 && cp <= 0x1f1ff && i + 1 < chars.length) {
      const cp2 = chars[i + 1].codePointAt(0)!;
      if (cp2 >= 0x1f1e6 && cp2 <= 0x1f1ff) {
        out.push(`${cp.toString(16)}-${cp2.toString(16)}`);
        i += 2; continue;
      }
    }
    out.push(cp.toString(16));
    i++;
  }
  return out;
}
